import React from 'react';
import { handleInputChange, handleKeyUp } from '../../utils/tableEvent';
import styles from './MainSearch.module.css';

const MainSearch = ({ filterFields, filters, setFilters, onSearch }) => {
  const handleSearchClick = (e) => {
    e.preventDefault();
    onSearch();
  };

  return (
    <div className={styles.searchSection}>
      <div className={styles.formGroupContainer}>
        {filterFields.map((field) => (
          <div key={field.id} className={styles.formGroup}>
            <label htmlFor={field.id}>{field.label}:</label>
            {field.type === 'text' ? (
              <input
                id={field.id}
                name={field.id}
                type="text"
                placeholder={field.placeholder}
                value={filters[field.id] || ''}
                onChange={(e) => handleInputChange(e, setFilters)}
                onKeyUp={(e) => handleKeyUp(e, handleSearchClick)} // Use handleSearchClick to ensure e.preventDefault
                style={{
                  width: field.width || 'auto',
                  height: field.height || 'auto',
                }}
              />
            ) : field.type === 'select' ? (
              <select
                id={field.id}
                name={field.id}
                value={filters[field.id] || ''}
                onChange={(e) => handleInputChange(e, setFilters)}
                style={{
                  width: field.width || 'auto',
                  height: field.height || 'auto',
                }}
              >
                {field.options.map((option) => (
                  <option key={option.value} value={option.value}>
                    {option.label}
                  </option>
                ))}
              </select>
            ) : null}
          </div>
        ))}
      </div>
      <div className={styles.buttonContainer}>
        <button onClick={handleSearchClick}>검색</button>
      </div>
    </div>
  );
};

export default MainSearch;